import{c as n}from"./app.8935f5f1.js";const l={},e=n('<h3 id="mysql-配置文件" tabindex="-1"><a class="header-anchor" href="#mysql-配置文件" aria-hidden="true">#</a> mysql 配置文件</h3><ul><li>my.conf (linux)</li><li>my.ini (win)</li></ul><div class="language-conf ext-conf"><pre class="language-conf"><code>[mysqld]\n#设置3306端口\nport = 3306\n# 设置mysql的安装目录\nbasedir=D:\\MySql\\mysql-5.7.29-winx64\n# 设置mysql数据库的数据的存放目录\ndatadir=D:\\MySql\\mysql-5.7.29-winx64\\data\n# 允许最大连接数\nmax_connections=200\n# 允许连接失败的次数。\nmax_connect_errors=10\n# 服务端使用的字符集默认为utf8mb4\ncharacter-set-server=utf8mb4\n# 创建新表时将使用的默认存储引擎\ndefault-storage-engine=INNODB\nexplicit_defaults_for_timestamp=true\nsql_mode=ONLY_FULL_GROUP_BY,NO_AUTO_VALUE_ON_ZERO,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION,PIPES_AS_CONCAT,ANSI_QUOTES\n[mysql]\n# 设置mysql客户端默认字符集\ndefault-character-set=utf8mb4\n[client]\n# 设置mysql客户端连接服务端时默认使用的端口\nport=3306\ndefault-character-set=utf8mb4\n</code></pre></div><ul><li>二进制日志文件 <code>log-bin</code></li><li>错误日志 <code>log-error</code></li><li>数据文件 <ul><li><strong>frm</strong> 文件 存放表结构</li><li><strong>myd</strong> 文件 存放表数据</li><li><strong>myi</strong> 文件 存放表索引</li></ul></li></ul><h3 id="mysql-总体架构" tabindex="-1"><a class="header-anchor" href="#mysql-总体架构" aria-hidden="true">#</a> mysql 总体架构</h3>',5);l.render=function(n,l){return e};export{l as default};
